 80	// GraphURLPathProps holds path variable values.  Currently all path variables are relevant only to a node graph
 81	export type GraphURLPathProps = {
 82	  aggregate: string;
 83	  aggregateValue: string;
 84	  app: string;
 85	  namespace: string;
 86	  service: string;
 87	  version: string;
 88	  workload: string;
 89	};
