 91	type ReduxDispatchProps = {
 92	  endTour: () => void;
 93	  onReady: (controller: any) => void;
 94	  setActiveNamespaces: (namespaces: Namespace[]) => void;
 95	  setEdgeMode: (edgeMode: EdgeMode) => void;
 96	  setGraphDefinition: (graphDefinition: GraphDefinition) => void;
 97	  setLayout: (layout: GraphLayout) => void;
