108	  activeNamespaces: Namespace[];
109	  activeTour?: TourInfo;
110	  boxByCluster: boolean;
111	  boxByNamespace: boolean;
112	  duration: DurationInSeconds; // current duration (dropdown) setting
113	  edgeLabels: EdgeLabelMode[];
