123	  namespaceLayout: GraphLayout;
124	  node?: NodeParamsType;
125	  rankBy: RankMode[];
126	  refreshInterval: IntervalInMilliseconds;
127	  replayActive: boolean;
128	  replayQueryTime: TimeInMilliseconds;
129	  showIdleEdges: boolean;
130	  showIdleNodes: boolean;
