144	type ReduxProps = ReduxStateProps & ReduxDispatchProps;
145	
146	export type GraphPageProps = Partial<GraphURLPathProps> &
147	  ReduxProps & {
148	    lastRefreshAt: TimeInMilliseconds; // redux by way of ConnectRefresh
149	  };
