151	export type GraphData = {
152	  elements: DecoratedGraphElements;
153	  elementsChanged: boolean; // true if current elements differ from previous fetch, can be used as an optimization.
154	  errorMessage?: string;
155	  fetchParams: FetchParams;
156	  isError?: boolean;
157	  isLoading: boolean;
158	  loaded: boolean;
159	  timestamp: TimeInMilliseconds;
160	};
