162	// GraphRefs are passed back from the graph when it is ready, to allow for
163	// other components, or test code, to manipulate the graph programatically.
164	export type GraphRefs = {
165	  getController: () => Controller;
166	  setSelectedIds: (values: string[]) => void;
167	};
