222	const GraphErrorBoundaryFallback = (): React.ReactElement => {
223	  return (
224	    <div className={graphContainerStyle}>
225	      <EmptyGraphLayout
226	        isError={true}
227	        isMiniGraph={false}
228	        loaded={false}
229	        namespaces={[]}
230	        refreshInterval={0}
231	        showIdleNodes={false}
232	        toggleIdleNodes={() => undefined}
233	      />
234	    </div>
