237	
238	class GraphPageComponent extends React.Component<GraphPageProps, GraphPageState> {
239	  private readonly errorBoundaryRef: any;
240	  private focusNode?: FocusNode;
241	  private graphDataSource: GraphDataSource;
242	
243	  static getNodeParamsFromProps(props: Partial<GraphURLPathProps>): NodeParamsType | undefined {
244	    const aggregate = props.aggregate;
245	    const aggregateOk = aggregate && aggregate !== UNKNOWN;
246	    const aggregateValue = props.aggregateValue;
247	    const aggregateValueOk = aggregateValue && aggregateValue !== UNKNOWN;
248	    const app = props.app;
249	    const appOk = app && app !== UNKNOWN;
250	    const namespace = props.namespace;
251	    const namespaceOk = namespace && namespace !== UNKNOWN;
252	    const service = props.service;
253	    const serviceOk = service && service !== UNKNOWN;
254	    const workload = props.workload;
255	    const workloadOk = workload && workload !== UNKNOWN;
256	    if (!aggregateOk && !aggregateValueOk && !appOk && !namespaceOk && !serviceOk && !workloadOk) {
257	      // @ts-ignore
258	      return;
259	    }
260	
261	    let nodeType: NodeType;
262	    let version: string | undefined;
263	    if (aggregateOk) {
264	      nodeType = NodeType.AGGREGATE;
265	      version = '';
266	    } else if (appOk || workloadOk) {
267	      nodeType = appOk ? NodeType.APP : NodeType.WORKLOAD;
268	      version = props.version;
269	    } else {
270	      nodeType = NodeType.SERVICE;
271	      version = '';
272	    }
273	    return {
274	      aggregate: aggregate!,
275	      aggregateValue: aggregateValue!,
276	      app: app!,
277	      cluster: getClusterName(),
278	      namespace: { name: namespace! },
279	      nodeType: nodeType,
280	      service: service!,
281	      version: version,
282	      workload: workload!
283	    };
284	  }
285	
286	  static isNodeChanged(prevNode?: NodeParamsType, node?: NodeParamsType): boolean {
287	    if (prevNode === node) {
288	      return false;
289	    }
290	    if ((prevNode && !node) || (!prevNode && node)) {
291	      return true;
292	    }
293	    if (prevNode && node) {
294	      const nodeAggregateHasChanged =
295	        prevNode.aggregate !== node.aggregate || prevNode.aggregateValue !== node.aggregateValue;
296	      const nodeAppHasChanged = prevNode.app !== node.app;
297	      const nodeServiceHasChanged = prevNode.service !== node.service;
298	      const nodeVersionHasChanged = prevNode.version !== node.version;
299	      const nodeTypeHasChanged = prevNode.nodeType !== node.nodeType;
300	      const nodeWorkloadHasChanged = prevNode.workload !== node.workload;
301	      return (
302	        nodeAggregateHasChanged ||
303	        nodeAppHasChanged ||
304	        nodeServiceHasChanged ||
305	        nodeVersionHasChanged ||
306	        nodeWorkloadHasChanged ||
307	        nodeTypeHasChanged
308	      );
309	    }
310	    return false;
311	  }
312	
313	  constructor(props: GraphPageProps) {
314	    super(props);
315	    this.errorBoundaryRef = React.createRef();
316	    const focusNodeId = getFocusSelector();
317	    if (focusNodeId) {
318	      this.focusNode = { id: focusNodeId, isSelected: true } as FocusNode;
319	      unsetFocusSelector();
320	    }
321	    this.graphDataSource = new GraphDataSource();
322	
323	    this.state = {
324	      graphData: {
325	        elements: { edges: [], nodes: [] },
326	        elementsChanged: false,
327	        fetchParams: this.graphDataSource.fetchParameters,
328	        isLoading: false,
329	        loaded: false,
330	        timestamp: 0
331	      },
332	      isReady: false,
333	      wizardsData: {
334	        showWizard: false,
335	        wizardType: '',
336	        updateMode: false,
337	        gateways: [],
338	        k8sGateways: [],
339	        peerAuthentications: [],
340	        namespace: ''
341	      },
342	      showConfirmDeleteTrafficRouting: false
343	    };
344	  }
345	
346	  componentDidMount(): void {
347	    // Connect to graph data source updates
348	    this.graphDataSource.on('loadStart', this.handleGraphDataSourceStart);
349	    this.graphDataSource.on('fetchError', this.handleGraphDataSourceError);
350	    this.graphDataSource.on('fetchSuccess', this.handleGraphDataSourceSuccess);
351	    this.graphDataSource.on('emptyNamespaces', this.handleGraphDataSourceEmpty);
352	
353	    // Let URL override current redux state at mount time.  We usually do this in
354	    // the constructor but it seems to work better here when the initial URL
355	    // is for a node graph.  When setting the node here it is available for the
356	    // loadGraphFromBackend() call.
357	    const urlNode = GraphPageComponent.getNodeParamsFromProps(this.props);
358	    if (GraphPageComponent.isNodeChanged(urlNode, this.props.node)) {
359	      // add the node namespace if necessary, but don't lose previously selected namespaces
360	      if (urlNode && !this.props.activeNamespaces.map(ns => ns.name).includes(urlNode.namespace.name)) {
361	        this.props.setActiveNamespaces([urlNode.namespace, ...this.props.activeNamespaces]);
362	      }
363	      this.props.setNode(urlNode);
364	    }
365	
366	    // trace url info
367	    const urlTrace = getTraceId();
368	    if (urlTrace !== this.props.trace?.traceID) {
369	      this.props.setTraceId(urlTrace);
370	    }
371	
372	    // layout url info
373	    const urlLayout = HistoryManager.getParam(URLParam.GRAPH_LAYOUT);
374	    if (urlLayout) {
375	      const validLayout = getValidGraphLayout(urlLayout);
376	      if (validLayout !== this.props.layout) {
377	        this.props.setLayout(validLayout);
378	        HistoryManager.setParam(URLParam.GRAPH_LAYOUT, validLayout);
379	      }
380	    } else {
381	      HistoryManager.setParam(URLParam.GRAPH_LAYOUT, this.props.layout);
382	    }
383	
384	    // Unless we are waiting for Manual refresh, ensure we initialize the graph.
385	    if (this.props.refreshInterval !== RefreshIntervalManual && HistoryManager.getRefresh() !== RefreshIntervalManual) {
386	      // Using setTimeout() ensures we wait for the toolbar to render and ensure all redux props are updated
387	      // with URL settings. That in turn ensures the initial fetchParams are correct.
388	      setTimeout(() => this.loadGraphDataFromBackend(), 0);
389	    }
390	  }
391	
392	  componentDidUpdate(prev: GraphPageProps): void {
393	    const curr = this.props;
394	
395	    const activeNamespacesChanged = !arrayEquals(
396	      prev.activeNamespaces,
397	      curr.activeNamespaces,
398	      (n1, n2) => n1.name === n2.name
399	    );
400	
401	    // we need to consider URL prop here because redux may not yet reflect any change applied in the Refresh component, and
402	    // the initial update needs to know whether to wait on fetching the graph data.
403	    const manualRefresh =
404	      curr.refreshInterval === RefreshIntervalManual || HistoryManager.getRefresh() === RefreshIntervalManual;
405	
406	    if (
407	      // refresh the graph but keep the side-panel
408	      (prev.lastRefreshAt !== curr.lastRefreshAt && curr.replayQueryTime === 0) ||
409	      (!manualRefresh &&
410	        (prev.duration !== curr.duration ||
411	          (prev.edgeLabels !== curr.edgeLabels && // test for edge labels that invoke graph gen appenders
412	            (curr.edgeLabels.includes(EdgeLabelMode.RESPONSE_TIME_GROUP) ||
413	              curr.edgeLabels.includes(EdgeLabelMode.THROUGHPUT_GROUP))) ||
414	          (prev.findValue !== curr.findValue && curr.findValue.includes('label:')) ||
415	          (prev.hideValue !== curr.hideValue && curr.hideValue.includes('label:')) ||
416	          (prev.refreshInterval !== curr.refreshInterval && curr.refreshInterval !== RefreshIntervalPause) ||
417	          prev.replayQueryTime !== curr.replayQueryTime ||
418	          prev.showSecurity !== curr.showSecurity ||
419	          prev.showVirtualServices !== curr.showVirtualServices ||
420	          prev.trafficRates !== curr.trafficRates))
421	    ) {
422	      this.loadGraphDataFromBackend();
423	    } else if (
424	      // refresh the graph and init the side-panel
425	      !manualRefresh &&
426	      (activeNamespacesChanged ||
427	        prev.boxByCluster !== curr.boxByCluster ||
428	        prev.boxByNamespace !== curr.boxByNamespace ||
429	        prev.graphType !== curr.graphType ||
430	        (prev.hideValue !== curr.hideValue && curr.hideValue.includes('label:')) ||
431	        (prev.replayActive !== curr.replayActive && !curr.replayActive) ||
432	        prev.showIdleEdges !== curr.showIdleEdges ||
433	        prev.showOperationNodes !== curr.showOperationNodes ||
434	        prev.showServiceNodes !== curr.showServiceNodes ||
435	        prev.showIdleNodes !== curr.showIdleNodes ||
436	        prev.showWaypoints !== curr.showWaypoints ||
437	        GraphPageComponent.isNodeChanged(prev.node, curr.node))
438	    ) {
439	      this.props.updateSummary(INITIAL_GRAPH_STATE.summaryData);
440	      this.loadGraphDataFromBackend();
441	    }
442	
443	    if (prev.layout !== curr.layout || prev.namespaceLayout !== curr.namespaceLayout || activeNamespacesChanged) {
444	      this.errorBoundaryRef.current.cleanError();
445	    }
446	
447	    if (curr.showLegend && this.props.activeTour) {
448	      this.props.endTour();
449	    }
450	  }
451	
452	  componentWillUnmount(): void {
453	    // Disconnect from graph data source updates
454	    this.graphDataSource.removeListener('loadStart', this.handleGraphDataSourceStart);
455	    this.graphDataSource.removeListener('fetchError', this.handleGraphDataSourceError);
456	    this.graphDataSource.removeListener('fetchSuccess', this.handleGraphDataSourceSuccess);
457	    this.graphDataSource.removeListener('emptyNamespaces', this.handleGraphDataSourceEmpty);
458	  }
459	
460	  render(): React.ReactNode {
461	    let conStyle = containerStyle;
462	    if (isKioskMode()) {
463	      conStyle = kioskContainerStyle;
464	    }
465	    const isEmpty = !(
466	      this.state.graphData.elements.nodes && Object.keys(this.state.graphData.elements.nodes).length > 0
467	    );
468	    const isReady = !(isEmpty || this.state.graphData.isError);
469	    const isReplayReady = this.props.replayActive && !!this.props.replayQueryTime;
470	    const refreshInterval = HistoryManager.getRefresh() ?? this.props.refreshInterval;
471	
472	    return (
473	      <>
474	        <FlexView className={conStyle} column={true}>
475	          <div>
476	            <GraphToolbar
477	              controller={this.state.graphRefs?.getController()}
478	              disabled={this.state.graphData.isLoading}
479	              elementsChanged={this.state.graphData.elementsChanged}
480	              onToggleHelp={this.toggleHelp}
481	            />
482	          </div>
483	          <FlexView grow={true} className={`${graphWrapperDivStyle} ${this.props.replayActive && replayBorder}`}>
484	            <ErrorBoundary
485	              ref={this.errorBoundaryRef}
486	              onError={this.notifyError}
487	              fallBackComponent={<GraphErrorBoundaryFallback />}
488	            >
489	              {this.props.showLegend && <GraphLegend closeLegend={this.props.toggleLegend} />}
490	              {isReady && (
491	                <Chip
492	                  className={`${graphTimeRange} ${this.props.replayActive ? replayBackground : graphBackground}`}
493	                  isReadOnly={true}
494	                >
495	                  {this.props.replayActive && <Badge style={{ marginRight: '4px' }} isRead={true}>{`Replay`}</Badge>}
496	                  {!isReplayReady && this.props.replayActive && `click Play to start`}
497	                  {!isReplayReady && !this.props.replayActive && `${this.displayTimeRange()}`}
498	                  {isReplayReady && `${this.displayTimeRange()}`}
499	                </Chip>
500	              )}
501	              {(!this.props.replayActive || isReplayReady) && (
502	                <div id="pft-graph" className={graphContainerStyle}>
503	                  <EmptyGraphLayout
504	                    action={this.handleEmptyGraphAction}
505	                    elements={this.state.graphData.elements}
506	                    error={this.state.graphData.errorMessage}
507	                    isLoading={this.state.graphData.isLoading}
508	                    isError={!!this.state.graphData.isError}
509	                    isMiniGraph={false}
510	                    loaded={this.state.graphData.loaded}
511	                    namespaces={this.props.activeNamespaces}
512	                    refreshInterval={refreshInterval}
513	                    showIdleNodes={this.props.showIdleNodes}
514	                    toggleIdleNodes={this.props.toggleIdleNodes}
515	                  >
516	                    <Graph
517	                      {...this.props}
518	                      focusNode={this.focusNode}
519	                      graphData={this.state.graphData}
520	                      isMiniGraph={false}
521	                      onDeleteTrafficRouting={this.handleDeleteTrafficRouting}
522	                      onLaunchWizard={this.handleLaunchWizard}
523	                      onReady={this.handleReady}
524	                    />
525	                  </EmptyGraphLayout>
526	                </div>
527	              )}
528	            </ErrorBoundary>
529	            {this.props.summaryData && (!this.props.replayActive || isReplayReady) && (
530	              <SummaryPanel
531	                data={this.props.summaryData}
532	                duration={this.state.graphData.fetchParams.duration}
533	                graphType={this.props.graphType}
534	                injectServiceNodes={this.props.showServiceNodes}
535	                isPageVisible={this.props.isPageVisible}
536	                namespaces={this.props.activeNamespaces}
537	                onDeleteTrafficRouting={this.handleDeleteTrafficRouting}
538	                onFocus={this.onFocus}
539	                onLaunchWizard={this.handleLaunchWizard}
540	                queryTime={this.state.graphData.timestamp / 1000}
541	                trafficRates={this.props.trafficRates}
542	                {...computePrometheusRateParams(this.props.duration, NUMBER_OF_DATAPOINTS)}
543	              />
544	            )}
545	          </FlexView>
546	        </FlexView>
547	        <ServiceWizard
548	          show={this.state.wizardsData.showWizard}
549	          type={this.state.wizardsData.wizardType}
550	          update={this.state.wizardsData.updateMode}
551	          namespace={this.state.wizardsData.namespace}
552	          cluster={this.state.wizardsData.serviceDetails?.service.cluster || ''}
553	          serviceName={this.state.wizardsData.serviceDetails?.service?.name || ''}
554	          workloads={this.state.wizardsData.serviceDetails?.workloads || []}
555	          subServices={this.state.wizardsData.serviceDetails?.subServices || []}
556	          createOrUpdate={
557	            canCreate(this.state.wizardsData.serviceDetails?.istioPermissions) ||
558	            canUpdate(this.state.wizardsData.serviceDetails?.istioPermissions)
559	          }
560	          virtualServices={this.state.wizardsData.serviceDetails?.virtualServices || []}
561	          destinationRules={this.state.wizardsData.serviceDetails?.destinationRules || []}
562	          gateways={this.state.wizardsData.gateways || []}
563	          k8sGateways={this.state.wizardsData.k8sGateways || []}
564	          k8sGRPCRoutes={this.state.wizardsData.serviceDetails?.k8sGRPCRoutes || []}
565	          k8sHTTPRoutes={this.state.wizardsData.serviceDetails?.k8sHTTPRoutes || []}
566	          peerAuthentications={this.state.wizardsData.peerAuthentications || []}
567	          tlsStatus={this.state.wizardsData.serviceDetails?.namespaceMTLS}
568	          onClose={this.handleWizardClose}
569	          istioAPIEnabled={this.props.istioAPIEnabled}
570	        />
571	        {this.state.showConfirmDeleteTrafficRouting && (
572	          <ConfirmDeleteTrafficRoutingModal
573	            isOpen={true}
574	            destinationRules={DestinationRuleC.fromDrArray(this.state.wizardsData.serviceDetails!.destinationRules)}
575	            virtualServices={this.state.wizardsData.serviceDetails!.virtualServices}
576	            k8sHTTPRoutes={this.state.wizardsData.serviceDetails!.k8sHTTPRoutes}
577	            k8sGRPCRoutes={this.state.wizardsData.serviceDetails!.k8sGRPCRoutes}
